const appointmentIds = $('Redis - Verificar Chave de Confirmação').item.json;
const dados = $('Dados').item.json;
return [{
  json: {
    appointment_ids: appointmentIds,
    telefone: dados.msg.telefone,
    chatId: `${dados.msg.telefone}@c.us`,
    texto_mensagem: (dados.msg.body || dados.msg.text || '').trim()
  }
}];

const raw = $json.choices[0].message.content.trim();
const dados = $('Extrair Dados da Confirmação').item.json;

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = { intencao: 'indefinido', resposta: 'Oi! Não entendi sua resposta. 😅\n\nPara *confirmar*, responda *CONFIRMO*.\nPara *cancelar*, responda *CANCELAR*.' };
}

const intencao = ['positivo', 'negativo', 'indefinido'].includes(parsed.intencao) ? parsed.intencao : 'indefinido';

return [{ json: { ...dados, intencao, resposta: parsed.resposta } }];

const dados = $json;
const phone = String(dados.telefone).replace('@c.us', '');
const ids = String(dados.appointment_ids).split(',').map(id => id.trim()).filter(Boolean);

const results = [];
for (const appointment_id of ids) {
  try {
    const resp = await $http.request({
      method: 'POST',
      url: 'http://bemp-mcp:8000/api/cancel_appointment',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ appointment_id: Number(appointment_id), phone })
    });
    results.push({ id: appointment_id, result: resp });
  } catch(e) {
    results.push({ id: appointment_id, error: e.message });
  }
}

return [{ json: { ...dados, cancelled: results, total: ids.length } }];
